#!/usr/bin/env node
/**
 * build-panel-css.mjs — compile panel.tailwind.css into a TS string module.
 *
 * Output: src/styles/panelTailwind.generated.ts (gitignored). Re-run on every
 * `npm run build` and `npm test`; the generated file is also produced by the
 * vitest globalSetup hook so a fresh checkout never sees the import as a 404.
 */

import { readFile, writeFile, mkdir } from "node:fs/promises";
import { existsSync } from "node:fs";
import path from "node:path";
import url from "node:url";
import postcss from "postcss";
import tailwind from "@tailwindcss/postcss";

const __filename = url.fileURLToPath(import.meta.url);
const ROOT = path.resolve(path.dirname(__filename), "..");
const INPUT = path.join(ROOT, "src/styles/panel.tailwind.css");
const OUTPUT = path.join(ROOT, "src/styles/panelTailwind.generated.ts");

export async function buildPanelCss() {
  const src = await readFile(INPUT, "utf8");
  const result = await postcss([tailwind()]).process(src, {
    from: INPUT,
    to: OUTPUT,
  });
  const css = result.css;
  // managedSheet rejects @import; if the postcss pipeline ever leaves one
  // behind, fail loudly here rather than at first paint.
  if (/^\s*@import\b/m.test(css)) {
    throw new Error(
      "build-panel-css: postcss output still contains @import. Tailwind v4 should flatten everything.",
    );
  }
  await mkdir(path.dirname(OUTPUT), { recursive: true });
  const banner =
    "// AUTO-GENERATED by scripts/build-panel-css.mjs. Do not edit. Gitignored.\n";
  // Wrap in String.raw so braces, backslashes, and unicode escapes survive
  // verbatim; close the raw template with a sentinel followed by closing
  // backtick so any embedded backticks in the CSS round-trip cleanly.
  const escaped = css.replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
  const body = `export const PANEL_TAILWIND_CSS = \`${escaped}\`;\n`;
  await writeFile(OUTPUT, banner + body, "utf8");
  return OUTPUT;
}

const isMain =
  import.meta.url === `file://${process.argv[1]}` ||
  import.meta.url === url.pathToFileURL(process.argv[1] ?? "").href;

if (isMain) {
  if (!existsSync(INPUT)) {
    console.error(`build-panel-css: input not found at ${INPUT}`);
    process.exit(1);
  }
  buildPanelCss()
    .then((out) => {
      // eslint-disable-next-line no-console
      console.log(`build-panel-css: wrote ${path.relative(ROOT, out)}`);
    })
    .catch((err) => {
      console.error("build-panel-css: failed", err);
      process.exit(1);
    });
}
